import React from "react";
import "./About.css";
import joeretz from "./images/joeretz.jpg";

function About() {
    return (
        <div className='about scrollspy' id='about'>
            <div className='about__container'>
                <div className='about__title'>
                    <h3>About Me</h3>
                </div>
                <div className='about__imageContainer'>
                    <img className='about__image' src={joeretz} alt='' />
                    <h4>Web Developer</h4>
                </div>
                <div className='about__info'>
                    <p>
                        I'm a self taught web developer 21 years old from Davao
                        De Oro, who loves to build experiences that help people
                        do what they couldn't do before. I love using technology
                        to enable others, and feel most fulfilled when using my
                        skills to do so. I'm a strong advocate for diversity and
                        inclusion in the tech industry.
                    </p>
                </div>
            </div>
        </div>
    );
}

export default About;
